SELECT DISTINCT date, CAST(EXTRACT(year FROM date) AS INTEGER) AS year, CAST(EXTRACT(month FROM date) AS INTEGER) AS month, regiao_sigla, estado_sigla, municipio, revenda, cnpj_da_revenda, nome_da_rua, numero_rua, complemento, bairro, cep, produto, unidade_de_medida, bandeira, valor_de_venda, valor_de_compra FROM (SELECT TRY_CAST(try_strptime(trim("data_da_coleta"), '%d/%m/%Y') AS DATE) AS date, NULLIF(TRIM("regiao_sigla"), '') AS regiao_sigla, NULLIF(TRIM("estado_sigla"), '') AS estado_sigla, NULLIF(TRIM("municipio"), '') AS municipio, NULLIF(TRIM("revenda"), '') AS revenda, NULLIF(TRIM("cnpj_da_revenda"), '') AS cnpj_da_revenda, NULLIF(TRIM("nome_da_rua"), '') AS nome_da_rua, NULLIF(TRIM("numero_rua"), '') AS numero_rua, NULLIF(TRIM("complemento"), '') AS complemento, NULLIF(TRIM("bairro"), '') AS bairro, NULLIF(TRIM("cep"), '') AS cep, NULLIF(TRIM("produto"), '') AS produto, NULLIF(TRIM("unidade_de_medida"), '') AS unidade_de_medida, NULLIF(TRIM("bandeira"), '') AS bandeira, TRY_CAST(replace(replace(trim("valor_de_venda"), '.', ''), ',', '.') AS DOUBLE) AS valor_de_venda, TRY_CAST(replace(replace(trim("valor_de_compra"), '.', ''), ',', '.') AS DOUBLE) AS valor_de_compra FROM "anp-brazil-shpc-dsas-ca-ca") WHERE date IS NOT NULL AND (valor_de_venda IS NOT NULL OR valor_de_compra IS NOT NULL)
